// Demonstrate the import/export patterns:
const utils = {
  // Named exports:
  formatDate: (date) => date.toLocaleDateString(),
  formatCurrency: (amount, currency = 'USD') => 
    new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(amount),

  // Default export equivalent:
  default: function createUtils() { return utils; }
};

// import { formatDate, formatCurrency } from './utils.js'
const { formatDate, formatCurrency } = utils;

console.log(formatCurrency(1234.56));
console.log(formatDate(new Date('2024-01-15')));

instruction:
Node.js was originally built on CommonJS (before ES Modules existed):

```js
// math.js (CommonJS)
const add = (a, b) => a + b;
module.exports = { add };
// OR: module.exports = add; (for single export)

// app.js
const { add } = require('./math');
const add2 = require('./math').add;
```

You'll still see CommonJS everywhere — npm packages, old codebases, config files.

starter:
// Simulating require/module.exports:
function createModule(exports) {
  return { require: () => exports };
}

// math.js equivalent:
const mathExports = { add: (a, b) => a + b, PI: 3.14159 };
const mathModule = createModule(mathExports);

// app.js equivalent:
const { add, PI } = mathModule.require();
console.log(add(5, 3));
console.log(PI);

// CommonJS also supports single-value exports:
const singleModule = createModule((a, b) => a * b);
const multiply = singleModule.require();
console.log(multiply(4, 7));

instruction:
A 'barrel' file (`index.js`) re-exports from multiple modules, creating a single import point:

```js
// utils/index.js
export { formatDate }  from './date.js';
export { formatCurrency } from './currency.js';
export { validateEmail } from './validation.js';

// app.js — import everything from one place:
import { formatDate, formatCurrency } from './utils';
```

Build a mini standard library using this pattern.

starter:
// Simulating a barrel module:
const stringUtils = {
  capitalize: str => str.charAt(0).toUpperCase() + str.slice(1),
  truncate: (str, max) => str.length > max ? str.slice(0, max) + '...' : str,
};
const numberUtils = {
  clamp: (num, min, max) => Math.min(Math.max(num, min), max),
  random: (min, max) => Math.floor(Math.random() * (max - min + 1)) + min,
};

// Barrel — re-export everything:
const utils = { ...stringUtils, ...numberUtils };

// Consumer imports from one place:
const { capitalize, truncate, clamp } = utils;
console.log(capitalize("javascript"));
console.log(truncate("This is a very long sentence.", 15));
console.log(clamp(150, 0, 100));

// Simulating dynamic import with a Promise:
async function loadChartModule() {
  console.log("Loading chart module...");
  // In real code: const { Chart } = await import('./chart.js');
  return new Promise(resolve => {
    setTimeout(() => {
      resolve({ renderChart: (data) => `Chart(${data.join(',')})` });
    }, 100);
  });
}

async function main() {
  const { renderChart } = await loadChartModule();
  console.log(renderChart([10, 20, 30]));
  console.log("Chart rendered!");
}

main();

